#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000
#define MAX_LEN 100

struct Post {
    int f, p;
    char s[MAX_LEN];
};

int compare(const void *a, const void *b) {
    struct Post *post1 = (struct Post *)a;
    struct Post *post2 = (struct Post *)b;
    return post2->p - post1->p;
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int special[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &special[i]);
    }
    struct Post posts[M];
    for (int i = 0; i < M; i++) {
        scanf("%d %d %s", &posts[i].f, &posts[i].p, posts[i].s);
    }
    struct Post special_posts[M], non_special_posts[M];
    int special_count = 0, non_special_count = 0;
    for (int i = 0; i < M; i++) {
        int is_special = 0;
        for (int j = 0; j < N; j++) {
            if (posts[i].f == special[j]) {
                is_special = 1;
                break;
            }
        }
        if (is_special) {
            special_posts[special_count++] = posts[i];
        } else {
            non_special_posts[non_special_count++] = posts[i];
        }
    }
    qsort(special_posts, special_count, sizeof(struct Post), compare);
    qsort(non_special_posts, non_special_count, sizeof(struct Post), compare);
    for (int i = 0; i < special_count; i++) {
        printf("%s\n", special_posts[i].s);
    }
    for (int i = 0; i < non_special_count; i++) {
        printf("%s\n", non_special_posts[i].s);
    }
    return 0;
}

