#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
using namespace std;

struct Post {
    int f, p;
    string s;
};

bool compare(const Post &a, const Post &b) {
    return a.p > b.p;
}

int main() {
    int N, M;
    cin >> N >> M;
    vector<int> special(N);
    for (int i = 0; i < N; i++) {
        cin >> special[i];
    }
    vector<Post> posts(M);
    for (int i = 0; i < M; i++) {
        cin >> posts[i].f >> posts[i].p >> posts[i].s;
    }
    vector<Post> special_posts, non_special_posts;
    for (int i = 0; i < M; i++) {
        bool is_special = false;
        for (int j = 0; j < N; j++) {
            if (posts[i].f == special[j]) {
                is_special = true;
                break;
            }
        }
        if (is_special) {
            special_posts.push_back(posts[i]);
        } else {
            non_special_posts.push_back(posts[i]);
        }
    }
    sort(special_posts.begin(), special_posts.end(), compare);
    sort(non_special_posts.begin(), non_special_posts.end(), compare);
    for (int i = 0; i < special_posts.size(); i++) {
        cout << special_posts[i].s << endl;
    }
    for (int i = 0; i < non_special_posts.size(); i++) {
        cout << non_special_posts[i].s << endl;
    }
    return 0;
}

