import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Post implements Comparable<Post> {
        int f, p;
        String s;
        Post(int f, int p, String s) {
            this.f = f;
            this.p = p;
            this.s = s;
        }
        @Override
        public int compareTo(Post o) {
            return o.p - this.p;
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt(), M = sc.nextInt();
        int[] special = new int[N];
        for (int i = 0; i < N; i++) {
            special[i] = sc.nextInt();
        }
        Post[] posts = new Post[M];
        for (int i = 0; i < M; i++) {
            posts[i] = new Post(sc.nextInt(), sc.nextInt(), sc.next());
        }
        Post[] special_posts = new Post[M], non_special_posts = new Post[M];
        int special_count = 0, non_special_count = 0;
        for (int i = 0; i < M; i++) {
            boolean is_special = false;
            for (int j = 0; j < N; j++) {
                if (posts[i].f == special[j]) {
                    is_special = true;
                    break;
                }
            }
            if (is_special) {
                special_posts[special_count++] = posts[i];
            } else {
                non_special_posts[non_special_count++] = posts[i];
            }
        }
        Arrays.sort(special_posts, 0, special_count);
        Arrays.sort(non_special_posts, 0, non_special_count);
        for (int i = 0; i < special_count; i++) {
            System.out.println(special_posts[i].s);
        }
        for (int i = 0; i < non_special_count; i++) {
            System.out.println(non_special_posts[i].s);
        }
    }
}

