const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInts() {
    return nextLine().split(' ').map(Number);
}

class Post {
    constructor(f, p, s) {
        this.f = f;
        this.p = p;
        this.s = s;
    }
}

let [N, M] = nextInts();
let special = nextInts();
let posts = [];
for (let i = 0; i < M; i++) {
    let [f, p, s] = nextLine().split(' ');
    f = Number(f);
    p = Number(p);
    posts.push(new Post(f, p, s));
}
let special_posts = posts.filter(post => special.includes(post.f));
let non_special_posts = posts.filter(post => !special.includes(post.f));
special_posts.sort((a, b) => b.p - a.p);
non_special_posts.sort((a, b) => b.p - a.p);
for (let post of special_posts) {
    console.log(post.s);
}
for (let post of non_special_posts) {
    console.log(post.s);
}

